+        // Prepare embeddings and geometries from extracted data.
+        let embeddings: Vec<Vec<f32>> = extracted.iter().map(|(_, e, _, _)| e.clone()).collect();
+        let geom: Vec<ViewpointGeometry> = extracted
+            .iter()
+            .map(|(_, _, az, pos)| ViewpointGeometry {
