+            coherence: coh,
+            n_viewpoints: n_valid,
+            n_effective: n_eff,
+        })
+    }
+
+    /// Access the event log.
+    pub fn events(&self) -> &[ViewpointFusionEvent] {
+        &self.events
+    }
+
+    /// Clear the event log.
+    pub fn clear_events(&mut self) {
+        self.events.clear();
+    }
