+        let mut indices: Vec<usize> = (0..n_sc).collect();
+        indices.sort_by(|&a, &b| {
+            avg_variance[b]
+                .partial_cmp(&avg_variance[a])
+                .unwrap_or(std::cmp::Ordering::Equal)
