+        let mut mode_energies = Vec::with_capacity(n_modes);
+        let mut explained = 0.0_f64;
+
+        for k in 0..n_modes {
+            let idx = indices[k];
+            // Create a unit vector along the highest-variance subcarrier
+            let mut mode = vec![0.0_f64; n_sc];
