+    #[test]
+    fn empty_frames_error() {
+        let mut aligner = PhaseAligner::new(3);
+        let result = aligner.align(&[]);
+        assert!(matches!(result, Err(PhaseAlignError::NoFrames)));
+    }
+
+    #[test]
+    fn phase_length_mismatch_error() {
