+            if d == 0 { j as f32 * 0.05 } else { j as f32 * 0.03 }
+        });
+        let pred = Array2::from_shape_fn((17, 2), |(j, d)| {
+            gt[[j, d]] + noise * ((j * 7 + d * 3) as f32).sin()
